class RewardModel(nn.Module):
    def __init__(self, base_model):
        super().__init__()
        self.base = base_model
        self.head = nn.Linear(base_model.config.d_model, 1)
    def forward(self, input_ids, mask):
        h = self.base(input_ids, mask).last_hidden_state[:, -1, :]
        return self.head(h)

def bradley_terry_loss(r_w, r_l):
    loss = -torch.log(torch.sigmoid(r_w - r_l) + 1e-8).mean()
    acc = (r_w > r_l).float().mean()
    return loss, acc

def ppo_loss(policy_lp, ref_lp, rewards, old_lp, eps=0.2, beta=0.05):
    ratio = (policy_lp - old_lp).exp()
    kl = policy_lp - ref_lp
    clipped = torch.clamp(ratio, 1-eps, 1+eps)
    adv = rewards - beta * kl
    loss = -torch.min(ratio * adv.detach(), clipped * adv.detach()).mean()
    return loss, kl.mean()

class AdaptiveKL:
    def __init__(self, beta=0.05, target=10.0):
        self.beta = beta; self.target = target
    def update(self, kl):
        if kl > 2*self.target: self.beta *= 1.5
        elif kl < 0.5*self.target: self.beta /= 1.5
        return self.beta

def dpo_loss(policy_w, policy_l, ref_w, ref_l, beta=0.1):
    r_w = beta * (policy_w - ref_w)
    r_l = beta * (policy_l - ref_l)
    loss = -F.logsigmoid(r_w - r_l).mean()
    acc = (r_w > r_l).float().mean()
    return loss, acc

# KTO — only needs preferred responses
def kto_loss(policy_lp, ref_lp, beta=0.1):
    reward = beta * (policy_lp - ref_lp)
    return (1 - F.sigmoid(reward)).mean()

